   210â†’	if req.Config != nil && req.Config.SystemInstruction != nil {
   211â†’		var text string
   212â†’		for _, p := range req.Config.SystemInstruction.Parts {
   213â†’			if p.Text != "" {
   214â†’				text += p.Text
   215â†’			}
   216â†’		}
   217â†’		if text != "" {
   218â†’			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   219â†’		}
   220â†’	}
   221â†’
   222â†’	// Conversation contents.
   223â†’	for _, c := range req.Contents {
   224â†’		role := mapRole(c.Role)
   225â†’
   226â†’		// Check each part: could be text, function_call, or function_response.
   227â†’		for _, p := range c.Parts {
   228â†’			switch {
   229â†’			case p.FunctionCall != nil:
   230â†’				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   231â†’				msgs = append(msgs, chatMessage{
   232â†’					Role: "assistant",
   233â†’					ToolCalls: []toolCall{{
   234â†’						ID:   p.FunctionCall.ID,
   235â†’						Type: "function",
   236â†’						Function: functionCall{
   237â†’							Name:      p.FunctionCall.Name,
   238â†’							Arguments: string(argsJSON),
   239â†’						},
   240â†’					}},
   241â†’				})
   242â†’			case p.FunctionResponse != nil:
   243â†’				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   244â†’				msgs = append(msgs, chatMessage{
   245â†’					Role:       "tool",
   246â†’					Content:    string(respJSON),
   247â†’					ToolCallID: p.FunctionResponse.ID,
   248â†’				})
   249â†’			case p.Text != "":
   250â†’				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   251â†’			}
   252â†’		}
   253â†’	}
   254â†’
   255â†’	// Merge consecutive assistant messages with tool_calls.
   256â†’	msgs = mergeAssistantToolCalls(msgs)
   257â†’
   258â†’	return msgs
   259â†’}
