   261â†’// mergeAssistantToolCalls combines adjacent assistant messages that each have
   262â†’// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   263â†’// one message rather than separate messages.
   264â†’func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   265â†’	if len(msgs) == 0 {
   266â†’		return msgs
   267â†’	}
   268â†’	var merged []chatMessage
   269â†’	for _, msg := range msgs {
   270â†’		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   271â†’			prev := &merged[len(merged)-1]
   272â†’			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   273â†’				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   274â†’				continue
   275â†’			}
   276â†’		}
   277â†’		merged = append(merged, msg)
   278â†’	}
   279â†’	return merged
   280â†’}
