    52â†’// GenerateContent converts the ADK request to an OpenAI chat completion request,
    53â†’// calls the API, and converts the response back to an LLMResponse.
    54â†’// Streaming is not implemented; the iterator always yields a single response.
    55â†’func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    56â†’	return func(yield func(*model.LLMResponse, error) bool) {
    57â†’		resp, err := m.doRequest(ctx, req)
    58â†’		if err != nil {
    59â†’			yield(nil, err)
    60â†’			return
    61â†’		}
    62â†’		yield(resp, nil)
    63â†’	}
    64â†’}
