   137â†’// --- request/response conversion ---
   138â†’
   139â†’func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   140â†’	msgs := convertContents(req)
   141â†’	tools := convertTools(req)
   142â†’
   143â†’	chatReq := chatRequest{
   144â†’		Model:    m.name,
   145â†’		Messages: msgs,
   146â†’		Tools:    tools,
   147â†’		Stream:   false,
   148â†’	}
   149â†’
   150â†’	if req.Config != nil {
   151â†’		chatReq.Temperature = req.Config.Temperature
   152â†’		chatReq.TopP = req.Config.TopP
