   179â†’		return nil, fmt.Errorf("openai: http request: %w", err)
   180â†’	}
   181â†’	defer httpResp.Body.Close()
   182â†’
   183â†’	respBody, err := io.ReadAll(httpResp.Body)
   184â†’	if err != nil {
   185â†’		return nil, fmt.Errorf("openai: read response: %w", err)
   186â†’	}
   187â†’
   188â†’	if httpResp.StatusCode != http.StatusOK {
   189â†’		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   190â†’	}
