   203â†’}
   204â†’
   205â†’// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   206â†’func convertContents(req *model.LLMRequest) []chatMessage {
   207â†’	var msgs []chatMessage
   208â†’
   209â†’	// System instruction.
   210â†’	if req.Config != nil && req.Config.SystemInstruction != nil {
   211â†’		var text string
   212â†’		for _, p := range req.Config.SystemInstruction.Parts {
   213â†’			if p.Text != "" {
   214â†’				text += p.Text
   215â†’			}
   216â†’		}
   217â†’		if text != "" {
   218â†’			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   219â†’		}
   220â†’	}
   221â†’
   222â†’	// Conversation contents.
   223â†’	for _, c := range req.Contents {
   224â†’		role := mapRole(c.Role)
   225â†’
   226â†’		// Check each part: could be text, function_call, or function_response.
   227â†’		for _, p := range c.Parts {
   228â†’			switch {
   229â†’			case p.FunctionCall != nil:
   230â†’				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   231â†’				msgs = append(msgs, chatMessage{
   232â†’					Role: "assistant",
   233â†’					ToolCalls: []toolCall{{
   234â†’						ID:   p.FunctionCall.ID,
   235â†’						Type: "function",
   236â†’						Function: functionCall{
   237â†’							Name:      p.FunctionCall.Name,
   238â†’							Arguments: string(argsJSON),
   239â†’						},
   240â†’					}},
   241â†’				})
   242â†’			case p.FunctionResponse != nil:
   243â†’				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   244â†’				msgs = append(msgs, chatMessage{
   245â†’					Role:       "tool",
   246â†’					Content:    string(respJSON),
   247â†’					ToolCallID: p.FunctionResponse.ID,
   248â†’				})
   249â†’			case p.Text != "":
   250â†’				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   251â†’			}
   252â†’		}
   253â†’	}
   254â†’
   255â†’	// Merge consecutive assistant messages with tool_calls.
   256â†’	msgs = mergeAssistantToolCalls(msgs)
   257â†’
   258â†’	return msgs
   259â†’}
   260â†’
   261â†’// mergeAssistantToolCalls combines adjacent assistant messages that each have
   262â†’// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   263â†’// one message rather than separate messages.
   264â†’func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   265â†’	if len(msgs) == 0 {
   266â†’		return msgs
   267â†’	}
   268â†’	var merged []chatMessage
   269â†’	for _, msg := range msgs {
   270â†’		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   271â†’			prev := &merged[len(merged)-1]
   272â†’			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   273â†’				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   274â†’				continue
   275â†’			}
   276â†’		}
   277â†’		merged = append(merged, msg)
   278â†’	}
   279â†’	return merged
   280â†’}
   281â†’
   282â†’// hasWebSearch checks whether the request contains a GoogleSearch tool marker,
   283â†’// indicating the caller wants web search capability.
   284â†’func hasWebSearch(req *model.LLMRequest) bool {
   285â†’	if req.Config == nil {
   286â†’		return false
   287â†’	}
   288â†’	for _, t := range req.Config.Tools {
   289â†’		if t != nil && t.GoogleSearch != nil {
   290â†’			return true
   291â†’		}
   292â†’	}
   293â†’	return false
   294â†’}
   295â†’
   296â†’// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   297â†’func convertTools(req *model.LLMRequest) []chatTool {
   298â†’	if req.Config == nil || len(req.Config.Tools) == 0 {
   299â†’		return nil
   300â†’	}
   301â†’
   302â†’	var tools []chatTool
   303â†’	for _, t := range req.Config.Tools {
   304â†’		if t.GoogleSearch != nil {
   305â†’			continue
   306â†’		}
   307â†’		for _, fd := range t.FunctionDeclarations {
   308â†’			ct := chatTool{
   309â†’				Type: "function",
   310â†’				Function: chatFunction{
   311â†’					Name:        fd.Name,
   312â†’					Description: fd.Description,
   313â†’				},
   314â†’			}
   315â†’			if fd.Parameters != nil {
   316â†’				ct.Function.Parameters = schemaToMap(fd.Parameters)
   317â†’			}
   318â†’			tools = append(tools, ct)
   319â†’		}
   320â†’	}
   321â†’	return tools
   322â†’}
   323â†’
   324â†’// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   325â†’// the OpenAI function parameters format (JSON Schema).
   326â†’func schemaToMap(s *genai.Schema) map[string]any {
   327â†’	m := map[string]any{}
   328â†’	if s.Type != "" {
   329â†’		m["type"] = strings.ToLower(string(s.Type))
   330â†’	}
   331â†’	if s.Description != "" {
   332â†’		m["description"] = s.Description
   333â†’	}
   334â†’	if len(s.Enum) > 0 {
   335â†’		m["enum"] = s.Enum
   336â†’	}
   337â†’	if s.Items != nil {
   338â†’		m["items"] = schemaToMap(s.Items)
   339â†’	}
   340â†’	if len(s.Properties) > 0 {
   341â†’		props := map[string]any{}
   342â†’		for k, v := range s.Properties {
   343â†’			props[k] = schemaToMap(v)
   344â†’		}
   345â†’		m["properties"] = props
   346â†’	}
   347â†’	if len(s.Required) > 0 {
   348â†’		m["required"] = s.Required
   349â†’	}
   350â†’	return m
   351â†’}
   352â†’
   353â†’// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   354â†’func convertResponse(resp *chatResponse) *model.LLMResponse {
   355â†’	llmResp := &model.LLMResponse{
   356â†’		TurnComplete: true,
   357â†’	}
   358â†’
   359â†’	if len(resp.Choices) == 0 {
   360â†’		llmResp.Content = genai.NewContentFromText("", "model")
   361â†’		return llmResp
   362â†’	}
   363â†’
   364â†’	choice := resp.Choices[0]
   365â†’	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   366â†’
   367â†’	content := &genai.Content{Role: "model"}
   368â†’
   369â†’	// Text content.
   370â†’	if choice.Message.Content != "" {
   371â†’		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   372â†’	}
   373â†’
   374â†’	// Tool calls.
   375â†’	for _, tc := range choice.Message.ToolCalls {
   376â†’		var args map[string]any
   377â†’		if tc.Function.Arguments != "" {
   378â†’			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   379â†’		}
   380â†’		content.Parts = append(content.Parts, &genai.Part{
   381â†’			FunctionCall: &genai.FunctionCall{
   382â†’				ID:   tc.ID,
   383â†’				Name: tc.Function.Name,
   384â†’				Args: args,
   385â†’			},
   386â†’		})
   387â†’	}
   388â†’
   389â†’	llmResp.Content = content
   390â†’
   391â†’	if resp.Usage != nil {
   392â†’		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   393â†’			PromptTokenCount:     resp.Usage.PromptTokens,
   394â†’			CandidatesTokenCount: resp.Usage.CompletionTokens,
   395â†’			TotalTokenCount:      resp.Usage.TotalTokens,
   396â†’		}
   397â†’	}
   398â†’
   399â†’	return llmResp
   400â†’}
   401â†’
   402â†’func mapRole(role string) string {
   403â†’	switch role {
   404â†’	case "model":
   405â†’		return "assistant"
   406â†’	default:
   407â†’		return role
   408â†’	}
   409â†’}
   410â†’
   411â†’func mapFinishReason(reason string) genai.FinishReason {
   412â†’	switch reason {
   413â†’	case "stop":
   414â†’		return genai.FinishReasonStop
   415â†’	case "length":
   416â†’		return genai.FinishReasonMaxTokens
   417â†’	case "tool_calls":
   418â†’		return genai.FinishReasonStop
   419â†’	case "content_filter":
   420â†’		return genai.FinishReasonSafety
   421â†’	default:
   422â†’		return genai.FinishReasonOther
   423â†’	}
   424â†’}
