func TestConvertInputs_FunctionCallAndResponse(t *testing.T) {
    req := &model.LLMRequest{
        Contents: []*genai.Content{
            genai.NewContentFromText("What releases?", "user"),
            {
                Role: "model",
                Parts: []*genai.Part{{
